PART = '    scene.render.filepath = VIDEO_PATH\n    scene.world.color = rgba("#F5E7CE")[:3]\n\n\ndef add_title():\n    bpy.ops.object.text_add(location=(0.0, 0.95, 0.02), rotation=(0.0, 0.0, 0.0))\n    title = bpy.context.active_object\n    title.name = "OyenPurba_Title"\n    title.data.body = "OYEN PURBA • 3D RIG V1"\n    title.data.align_x = "CENTER"\n    title.data.size = 0.24\n    title.data.extrude = 0.006\n\n\ndef main():\n    os.makedirs(OUTPUT_ROOT, exist_ok=True)\n    log(f"Starting rigged job {JOB.get(\'job_id\', \'unknown\')}")\n    clear_scene()\n    configure_scene()\n    add_environment()\n    rig, tail_points = create_armature()\n    create_oyen_purba(rig, tail_points)\n    camera = create_camera()\n    animate_rig(rig, camera)\n    add_title()\n    bpy.context.scene.frame_set(1)\n    bpy.ops.wm.save_as_mainfile(filepath=BLEND_PATH)\n    log(f"Rig ready: {len(rig.data.bones)} bones")\n    log(f"Blend saved: {BLEND_PATH}")\n    bpy.ops.render.render(animation=True)\n    log(f"Video rendered: {VIDEO_PATH}")\n    print(f"OYEN_RIG_READY bones={len(rig.data.bones)}")\n    print("OYEN_WORKER_SUCCESS")\n\n\nif __name__ == "__main__":\n    try:\n        main()\n    except Exception as exc:\n        print(f"OYEN_WORKER_ERROR: {exc}")\n        print(traceback.format_exc())\n        raise\n'